{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental structural change to the aggregate root, not a minor field addition. It redefines what a Shipment *is* — from a single delivery obligation to a potentially multi-stop, multi-party delivery obligation. This affects pricing, routing, tracking, proof-of-delivery, SLA measurement, and every downstream system that consumes shipment data.",
    "bounded_context": "Shipment Management / Order Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A logistical unit representing the movement of goods from origin to one or more recipients. Post-change, a Shipment is a delivery plan that may involve multiple stops." },
      { "term": "Recipient", "definition": "A named party who receives goods at a specific address, with contact information and delivery preferences. Recipients are now a collection within a Shipment rather than a singular embedded value." },
      { "term": "Delivery Preference", "definition": "Recipient-specific instructions governing how, when, and where delivery should occur (e.g., leave at door, signature required, time window, safe place). NEW concept — did not exist as a first-class entity before." },
      { "term": "Primary Recipient", "definition": "PROPOSED: The first or designated main recipient on a multi-recipient shipment. Critical for backward compatibility — must be defined if external APIs expect a single recipient." },
      { "term": "Delivery Stop", "definition": "PROPOSED: A discrete delivery point within a multi-recipient shipment. Each Recipient maps to one Delivery Stop. Ordering of stops becomes a new domain concern." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. Previously simple (pending → in-transit → delivered). Now must account for partial delivery scenarios where some recipients have received goods and others have not." },
      { "term": "Proof of Delivery (POD)", "definition": "Evidence that goods were delivered. Previously one POD per Shipment. Now requires one POD per Recipient within a Shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery obligation and represents a corrupt state — goods with no destination.",
      "testable_assertion": "Creating or updating a Shipment with an empty Recipients collection MUST fail validation."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment MUST have a name, address, and phone number. These are non-optional fields.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to execute a physical delivery. Without them, a courier cannot complete the delivery, and the shipment data is incomplete.",
      "testable_assertion": "Adding a Recipient with a null or empty name, address, or phone number MUST fail validation."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment MUST have Delivery Preferences. If none are specified, system defaults apply.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy enhancement. Defaulting is acceptable; the system operated without explicit preferences before.",
      "testable_assertion": "A Recipient created without explicit delivery preferences MUST have system-default preferences applied automatically."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments MUST remain valid and queryable after the model change. Migration must preserve the existing Recipient as the sole entry in the Recipients collection.",
      "invariant": true,
      "invariant_justification": "Loss or corruption of 2 million production shipment records is a data integrity catastrophe. Backward compatibility is a hard constraint, not a preference.",
      "testable_assertion": "After migration, every pre-existing Shipment MUST return exactly one Recipient with identical name, address, and phone to the original record."
    },
    {
      "id": "BR-5",
      "rule": "Shipment status must reflect the aggregate delivery state across all Recipients. A Shipment is only 'Delivered' when ALL Recipients have received their goods.",
      "invariant": true,
      "invariant_justification": "A shipment reported as delivered when some recipients have not received goods is a lie about physical reality. It breaks SLA measurement, billing, and customer trust.",
      "testable_assertion": "A Shipment with 3 Recipients where only 2 have PODs recorded MUST NOT have status 'Delivered'. It must reflect a partial-delivery or in-progress state."
    },
    {
      "id": "BR-6",
      "rule": "External partner APIs MUST continue to receive shipment data in a compatible format during and after the transition. A designated Primary Recipient or flattened single-recipient projection must be available.",
      "invariant": false,
      "invariant_justification": "This is a contractual and integration policy, not a state integrity rule. Partners can be migrated over time, and the compatibility layer is a transitional business decision.",
      "testable_assertion": "External API responses for existing single-recipient shipments MUST return identical JSON structure to the pre-change format. Multi-recipient shipments MUST either use a versioned endpoint or include a primary_recipient field for backward compatibility."
    },
    {
      "id": "BR-7",
      "rule": "Proof of Delivery must be captured per-Recipient, not per-Shipment.",
      "invariant": true,
      "invariant_justification": "POD is evidence of a physical event at a specific address for a specific person. A single POD for multiple recipients at different addresses is physically meaningless and legally indefensible.",
      "testable_assertion": "Each Recipient within a Shipment MUST have an independent POD record. A Shipment-level POD without Recipient attribution MUST be rejected."
    },
    {
      "id": "BR-8",
      "rule": "Recipients within a Shipment must have a defined delivery order (sequence). The platform must determine or allow specification of stop ordering.",
      "invariant": false,
      "invariant_justification": "Ordering is a routing optimization and business preference, not a data integrity constraint. Different dispatch strategies may reorder stops.",
      "testable_assertion": "Each Recipient in a multi-recipient Shipment MUST have a sequence number. The system MUST NOT deliver to recipients in an undefined/random order."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The sender specifies 3 Recipients with different addresses and delivery preferences",
      "then": "The Shipment is created with all 3 Recipients, each preserving their individual address, contact info, and delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "An existing production Shipment created before the model change",
      "when": "The Shipment is queried via any API or internal service",
      "then": "It returns a Recipients collection containing exactly one Recipient with the original name, address, and phone number"
    },
    {
      "id": "AC-3",
      "given": "A Shipment with 2 Recipients where Recipient A has been delivered to",
      "when": "The Shipment status is queried",
      "then": "The status is 'Partially Delivered' (or equivalent), NOT 'Delivered'"
    },
    {
      "id": "AC-4",
      "given": "An external partner API consumer requests a multi-recipient Shipment",
      "when": "The partner is using the v1 (pre-change) API contract",
      "then": "The response includes the Primary Recipient in the legacy single-recipient field structure, and the partner does not experience a breaking change"
    },
    {
      "id": "AC-5",
      "given": "A Shipment creation request with zero Recipients",
      "when": "The request is submitted",
      "then": "The system rejects it with a validation error; no Shipment is persisted"
    },
    {
      "id": "AC-6",
      "given": "A courier completes delivery to one Recipient of a multi-recipient Shipment",
      "when": "Proof of Delivery is submitted",
      "then": "The POD is recorded against that specific Recipient, not the Shipment as a whole"
    },
    {
      "id": "AC-7",
      "given": "A Shipment with multiple Recipients",
      "when": "Any Recipient is added without delivery preferences",
      "then": "System-default delivery preferences are applied to that Recipient"
    },
    {
      "id": "AC-8",
      "given": "2 million existing shipments in production",
      "when": "The data migration runs",
      "then": "All 2 million shipments are migrated without data loss, downtime is within the agreed maintenance window, and rollback capability exists"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where two Recipients share the same address but have different delivery preferences",
      "expected_behavior": "Both Recipients are treated as distinct delivery obligations. Each gets their own POD. Preferences are honored individually even though the physical address is the same."
    },
    {
      "scenario": "A Recipient is removed from a multi-recipient Shipment after the Shipment is already in transit",
      "expected_behavior": "The system must define whether mid-transit recipient removal is allowed. If allowed, already-delivered Recipients retain their POD. If the removed Recipient had goods allocated, a return or rerouting process must trigger. This needs product decision."
    },
    {
      "scenario": "All Recipients on a Shipment have delivery failures (e.g., address not found, refused)",
      "expected_behavior": "Shipment status becomes 'Failed' or 'All Deliveries Failed'. Return-to-sender or exception handling process initiates for the entire Shipment."
    },
    {
      "scenario": "External partner sends a shipment update using the old single-recipient schema for a shipment that now has multiple recipients",
      "expected_behavior": "The system must reject or map this intelligently. Updating the Primary Recipient only while preserving other recipients is the safest approach. Silent data loss of non-primary recipients is unacceptable."
    },
    {
      "scenario": "A Shipment is created with one Recipient, then additional Recipients are added later after initial dispatch",
      "expected_behavior": "This is a mid-lifecycle mutation. The system must determine if re-routing is possible, update the courier's stop list, and recalculate SLAs. If the Shipment is already delivered, adding recipients must be rejected."
    },
    {
      "scenario": "Pricing and billing: a single-recipient shipment costs X. Does a 3-recipient shipment cost X or 3X or something else?",
      "expected_behavior": "Pricing model must be explicitly defined. Multi-stop shipments typically have a base rate plus per-stop surcharges. Existing single-recipient pricing must remain unchanged for backward compatibility."
    },
    {
      "scenario": "Notification delivery: who receives tracking updates for a multi-recipient Shipment?",
      "expected_behavior": "Each Recipient should receive notifications relevant to their specific delivery. The sender receives aggregate updates. A Recipient should NOT see other Recipients' delivery details (privacy)."
    },
    {
      "scenario": "SLA measurement: a Shipment promises delivery by 5 PM. Recipient A is delivered at 3 PM, Recipient B at 6 PM.",
      "expected_behavior": "The Shipment-level SLA is breached. Per-Recipient SLAs may also be needed. SLA measurement must operate at the Recipient level, not just Shipment level."
    }
  ],

  "business_impact": {
    "financial": "HIGH IMPACT. Pricing model must be redesigned for multi-stop shipments — this is a revenue model change, not just a technical one. Migration costs include engineering effort, testing, and potential downtime. Partner API changes may require renegotiation of integration contracts. Incorrect SLA measurement post-change could trigger penalty clauses.",
    "operational": "HIGH IMPACT. Courier routing algorithms must support multi-stop optimization. Dispatch and fleet management must handle variable-length stop lists. Warehouse operations may need to batch goods by shipment differently. Customer support must understand partial delivery states — new training required. POD collection workflow changes for couriers in the field.",
    "user": "MEDIUM-HIGH IMPACT. Senders gain a powerful new capability (multi-recipient). Recipients experience per-recipient tracking and preferences — improved UX. However, partial delivery states are a new concept that may confuse end users. Notification volume increases. Existing single-recipient users must experience zero disruption.",
    "risk": "HIGH. Data migration of 2M records is the primary risk — any corruption is catastrophic. External partner API breakage could cause immediate business disruption. Introduction of a 'Partially Delivered' state is a new operational concept that must flow through every downstream system (billing, reporting, analytics, support tools). If Shipment status logic is not updated atomically with the model change, there will be a window where shipments can reach logically impossible states.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain multi-recipient capability. Must understand new pricing. Existing workflows unchanged for single-recipient shipments." },
      { "group": "Recipients", "impact": "Receive per-recipient delivery preferences and tracking. Privacy concern: must not see other recipients' data." },
      { "group": "Couriers/Drivers", "impact": "Must handle multi-stop routes. POD collection changes from per-shipment to per-recipient. Mobile app updates required." },
      { "group": "External API Partners", "impact": "Breaking change risk. Require v1 compatibility layer or coordinated migration. May need new API version documentation and migration timeline." },
      { "group": "Customer Support", "impact": "Must understand partial delivery states. New resolution workflows for per-recipient issues within a single shipment. Training required." },
      { "group": "Finance/Billing", "impact": "Pricing model redesign. Per-recipient vs per-shipment billing questions. SLA penalty recalculation logic." },
      { "group": "Analytics/Reporting", "impact": "All delivery metrics change — delivery rate, SLA compliance, cost-per-delivery now have a per-recipient dimension. Historical reporting must handle both models." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is directionally clear but critically incomplete. It states 'one or more Recipients' and 'different delivery preferences' but does not define: (1) what delivery preferences consist of, (2) the concept of a Primary Recipient for backward compatibility, (3) how Shipment status maps to multi-recipient states, (4) the pricing model, (5) SLA measurement per-recipient vs per-shipment, (6) the partner API migration strategy, or (7) whether mid-lifecycle recipient mutation is allowed. These are not implementation details — they are business decisions that change the domain model's semantics. Without them, any implementation is guessing.",
    "high_confidence_areas": [
      "At-least-one Recipient invariant",
      "Required Recipient fields (name, address, phone) carry forward",
      "Data migration must preserve all 2M existing records exactly",
      "POD must be per-Recipient in multi-recipient model",
      "External partner backward compatibility is required"
    ],
    "low_confidence_areas": [
      "Definition and structure of 'delivery preferences' — completely unspecified",
      "Shipment status model for partial delivery states",
      "Pricing and billing model for multi-recipient shipments",
      "Primary Recipient designation — whether it exists and how it's determined",
      "Mid-lifecycle mutations (adding/removing recipients after dispatch)",
      "SLA measurement granularity",
      "Partner API migration strategy and timeline"
    ],
    "assumptions": [
      "Delivery preferences are per-Recipient, not shared across the Shipment",
      "A 'Partially Delivered' status or equivalent will be introduced",
      "External partner APIs currently use a REST-based contract with a single-recipient JSON schema",
      "The migration must be online or within a short maintenance window — 2M records rules out extended downtime",
      "Existing single-recipient shipments must be indistinguishable from new single-recipient shipments post-migration"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'different delivery preferences' but does not define what a Delivery Preference is. Is it time windows? Signature requirements? Safe-place instructions? Contactless delivery? This is a new first-class domain concept with no definition.",
      "affected_stakeholders": ["Recipients", "Couriers/Drivers", "Product Team", "Engineering"],
      "options": [
        "Define a minimal set of delivery preferences (e.g., time window, signature required, safe place instructions) and ship incrementally",
        "Make delivery preferences a flexible key-value bag — maximally extensible but harder to validate",
        "Defer delivery preferences to a follow-up and only ship multi-recipient structure now"
      ],
      "recommendation": "Define a concrete, bounded set of delivery preferences as a value object before implementation begins. An undefined concept cannot be correctly implemented."
    },
    {
      "type": "ambiguity",
      "description": "No definition of Shipment status semantics for multi-recipient scenarios. The current model likely has statuses like Pending, In Transit, Delivered, Failed. Multi-recipient shipments introduce Partially Delivered, which cascades through billing, SLAs, reporting, and partner APIs.",
      "affected_stakeholders": ["Customer Support", "Finance/Billing", "Analytics/Reporting", "External API Partners"],
      "options": [
        "Introduce Recipient-level statuses and derive Shipment status from aggregation rules",
        "Keep Shipment status simple and add a separate per-Recipient tracking model"
      ],
      "recommendation": "Introduce explicit Recipient-level delivery status and define clear aggregation rules for Shipment-level status. This must be specified before implementation."
    },
    {
      "type": "ambiguity",
      "description": "No Primary Recipient concept defined. External partners expect a single recipient. For multi-recipient shipments, which recipient is surfaced to legacy consumers? First added? Explicitly designated? This is a business decision, not an implementation detail.",
      "affected_stakeholders": ["External API Partners", "Engineering"],
      "options": [
        "First Recipient in the collection is implicitly Primary",
        "Sender explicitly designates a Primary Recipient",
        "Require all partners to migrate to v2 API with a deadline"
      ],
      "recommendation": "Require explicit Primary Recipient designation by the sender. Implicit rules create ambiguity and will cause partner integration bugs."
    },
    {
      "type": "missing_context",
      "description": "Pricing model for multi-recipient shipments is undefined. This is a revenue-critical decision that must precede implementation because it affects the Shipment aggregate's cost calculation, invoicing, and partner billing contracts.",
      "affected_stakeholders": ["Finance/Billing", "Senders/Shippers", "Product Team"],
      "options": [
        "Flat rate per Shipment regardless of recipients",
        "Base rate + per-additional-recipient surcharge",
        "Per-recipient pricing (effectively N independent deliveries bundled)"
      ],
      "recommendation": "Finance and Product must define the pricing model before engineering begins. The chosen model affects the domain entity structure (e.g., whether cost is on Shipment or Recipient)."
    }
  ],

  "rejection_reasons": []
}

